import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Preguntas Frecuentes para Jugadores","description":"Preguntas frecuentes para jugadores y administradores de servidores relacionadas con Fabric.","frontmatter":{"title":"Preguntas Frecuentes para Jugadores","description":"Preguntas frecuentes para jugadores y administradores de servidores relacionadas con Fabric.","files":[]},"headers":[],"relativePath":"es_es/1.21.8/players/faq.md","filePath":"versions/1.21.8/translated/es_es/players/faq.md","lastUpdated":1760721669000}`);var a={name:`es_es/1.21.8/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Preguntas Frecuentes para Jugadores <a class="header-anchor" href="#h1" aria-label="Permalink to “Preguntas Frecuentes para Jugadores”">​</a></h1><p>Hay varias preguntas que se hacen con frecuencia, por lo que hemos compilado una lista de ellas aquí.</p><h2 id="preguntas-generales" tabindex="-1">Preguntas Generales <a class="header-anchor" href="#preguntas-generales" aria-label="Permalink to “Preguntas Generales”">​</a></h2><h3 id="¿que-versiones-de-minecraft-son-compatibles-con-fabric" tabindex="-1">¿Qué versiones de Minecraft son compatibles con Fabric? <a class="header-anchor" href="#¿que-versiones-de-minecraft-son-compatibles-con-fabric" aria-label="Permalink to “¿Qué versiones de Minecraft son compatibles con Fabric?”">​</a></h3><p>Oficialmente, Fabric es compatible con todas las versiones de Minecraft empezando desde la snapshot <code>18w43b</code> en adelante, y la versión de salida <code>1.14</code> en adelante.</p><h3 id="¿donde-puedo-descargar-mods-de-fabric-publicados" tabindex="-1">¿Donde puedo descargar mods de Fabric publicados? <a class="header-anchor" href="#¿donde-puedo-descargar-mods-de-fabric-publicados" aria-label="Permalink to “¿Donde puedo descargar mods de Fabric publicados?”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Siempre debes asegurarte que los mods sean de una fuente confiable. Visita la guía de <a href="./finding-mods">Encontrar Mods Confiables</a> para mayor información.</p></div><p>La mayoría de desarrolladores publican sus mods en <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> y <a href="https://www.curseforge.com/minecraft/search?page=1&amp;pageSize=20&amp;sortType=1&amp;class=mc-mods&amp;gameFlavorsIds=4" target="_blank" rel="noreferrer">CurseForge</a>, aunque algunos prefieren subir sus mods en sus páginas web personales, o en otras plataformas, como sus repositorios de Github.</p><h3 id="¿donde-puedo-encontrar-modpacks-para-fabric" tabindex="-1">¿Dónde puedo encontrar modpacks para Fabric? <a class="header-anchor" href="#¿donde-puedo-encontrar-modpacks-para-fabric" aria-label="Permalink to “¿Dónde puedo encontrar modpacks para Fabric?”">​</a></h3><p>Puedes encontrar modpacks para Fabric en varias plataformas, como:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};